import React, { useState } from 'react';
import { View, Button, Text, Linking } from 'react-native';
import * as AuthSession from 'expo-auth-session';

const CLIENT_ID = 'mobile_app_client_123';
const REDIRECT_URI = AuthSession.makeRedirectUri();
const AUTHORIZATION_ENDPOINT = 'https://example.com/oauth/authorize';
const TOKEN_ENDPOINT = 'https://example.com/oauth/token';

export default function App() {
  const [authToken, setAuthToken] = useState(null);

  const handleOAuthLogin = async () => {
    const authUrl = `${AUTHORIZATION_ENDPOINT}?response_type=code&client_id=${CLIENT_ID}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}`;
    const result = await AuthSession.startAsync({ authUrl });

    if (result.type === 'success') {
      const { code } = result.params;
      exchangeCodeForToken(code);
    }
  };

  const exchangeCodeForToken = async (code) => {
    try {
      const response = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=authorization_code&code=${code}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&client_id=${CLIENT_ID}`,
      });

      const data = await response.json();
      if (data.access_token) {
        setAuthToken(data.access_token);
      }
    } catch (error) {
      console.error('Error exchanging code for token:', error);
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      {authToken ? (
        <Text>Authenticated! Token: {authToken}</Text>
      ) : (
        <Button title="Login with OAuth" onPress={handleOAuthLogin} />
      )}
    </View>
  );
}